// src/cli/init.ts
async function checkExistingInstallation(targetDir) {
  const layout = getProviderLayout();
  const rootDir = join10(targetDir, layout.rootDir);
  return fileExists(rootDir);
}
var PROVIDER_SUBDIR_COMPONENTS = new Set([
  "rules",
  "hooks",
  "contexts",
  "agents",
  "skills",
  "ontology"
]);
function componentToPath(targetDir, component) {
  if (component === "entry-md") {
    const layout = getProviderLayout();
    return join10(targetDir, layout.entryFile);
  }
  if (PROVIDER_SUBDIR_COMPONENTS.has(component)) {
    const layout = getProviderLayout();
    return join10(targetDir, layout.rootDir, component);
  }
  return join10(targetDir, component);
}
function buildInstalledPaths(targetDir, components) {
  return components.map((component) => componentToPath(targetDir, component));
}
function logItems(items, formatter) {
  for (const item of items) {
    formatter(item);
  }
}
function logSuccessDetails(installedPaths, skippedComponents) {
  console.log(i18n.t("cli.init.success"));
  console.log(`
Installed paths:`);
  logItems(installedPaths, (path2) => console.log(`  - ${path2}`));
  if (skippedComponents.length > 0) {
    console.log(`
Skipped (already exist):`);
    logItems(skippedComponents, (component) => console.log(`  - ${component}`));
  }
}
function createFailureResult(errorMessage) {
  return {
    success: false,
    message: i18n.t("cli.init.failed"),
    errors: [errorMessage]
  };
}
function logInstallResultInfo(result) {
  logItems(result.backedUpPaths, (path2) => console.log(i18n.t("cli.init.backedUp", { path: path2 })));
  logItems(result.warnings, (warning) => console.warn(`Warning: ${warning}`));
}
async function resolveOptions(options) {
  if (isInteractiveMode(options.yes)) {
    const result = await runInitWizard({
      yes: options.yes,
      lang: options.lang,
      domain: options.domain
    });
    if (result.cancelled)
      return null;
    return { lang: result.lang, domain: result.domain };
  }
  const defaults = getDefaultWizardResult({
    yes: options.yes,
    lang: options.lang,
    domain: options.domain
  });
  return { lang: defaults.lang, domain: defaults.domain };
}
async function setupMcpConfig(targetDir) {
  const uvAvailable = await checkUvAvailable();
  if (uvAvailable) {
    try {
      await generateMCPConfig(targetDir);
    } catch (error2) {
      const msg = error2 instanceof Error ? error2.message : String(error2);
      console.warn(`Warning: Failed to setup MCP environment: ${msg}`);
    }
  } else {
    console.warn("Warning: uv not found. Skipping MCP server configuration.");
    console.warn("Install uv (https://docs.astral.sh/uv/) to enable MCP integration.");
  }
}
async function initCommand(options) {
  const targetDir = process.cwd();
  const resolved = await resolveOptions(options);
  if (!resolved) {
    return { success: false, message: i18n.t("cli.init.wizard.cancelled") };
  }
  console.log(i18n.t("cli.init.start"));
  try {
    const layout = getProviderLayout();
    const exists2 = await checkExistingInstallation(targetDir);
    if (exists2) {
      console.log(i18n.t("cli.init.exists", { rootDir: layout.rootDir }));
      console.log(i18n.t("cli.init.backing_up"));
    }
    console.log(i18n.t("cli.init.copying"));
    const installResult = await install({
      targetDir,
      language: resolved.lang,
      force: options.force ?? false,
      backup: exists2,
      domain: resolved.domain
    });
    if (!installResult.success) {
      return createFailureResult(installResult.error || "Unknown error");
    }
    const installedPaths = buildInstalledPaths(targetDir, installResult.installedComponents);
    logInstallResultInfo(installResult);
    logSuccessDetails(installedPaths, installResult.skippedComponents);
    await setupMcpConfig(targetDir);
    try {
      const existing = await readLockFile(targetDir);
      await writeLockFile(targetDir, package_default.version, existing);
    } catch {}
    console.log("");
    console.log("Required plugins (install manually):");
    console.log("  /plugin marketplace add obra/superpowers-marketplace");
    console.log("  /plugin install superpowers");
    console.log("  /plugin install superpowers-developing-for-claude-code");
    console.log("  /plugin install elements-of-style");
    console.log("  /plugin install context7");
    console.log("");
    console.log('See CLAUDE.md "мҷёл¶Җ мқҳмЎҙм„ұ" section for details.');
    return {
      success: true,
      message: i18n.t("cli.init.success"),
      installedPaths
    };
  } catch (error2) {
    const errorMessage = error2 instanceof Error ? error2.message : String(error2);
    console.error(i18n.t("cli.init.failed"), errorMessage);
    return createFailureResult(errorMessage);
  }
}

